class Solution:
    def minPathCost(self, grid, moveCost):
        from functools import lru_cache
        m, n = len(grid), len(grid[0])
        INF = float('inf')
        @lru_cache(maxsize=None)
        def dfs(r, c):
            cost = grid[r][c]
            if r == m - 1:
                return cost
            sub = INF
            for nc in range(n):
                sub = min(sub, moveCost[grid[r][c]][nc] + dfs(r + 1, nc))
            return cost + sub
        ans = INF
        for c in range(n):
            ans = min(ans, dfs(0, c))
        return ans

