class Solution:
    def minPathCost(self, grid, moveCost):
        m, n = len(grid), len(grid[0])
        dp = list(grid[0])
        for r in range(1, m):
            ndp = [float('inf')] * n
            for j in range(n):
                best = float('inf')
                for p in range(n):
                    cand = dp[p] + moveCost[grid[r - 1][p]][j]
                    if cand < best:
                        best = cand
                ndp[j] = grid[r][j] + best
            dp = ndp
        return min(dp)

