var minPathCost = function(grid, moveCost) {
    const m = grid.length, n = grid[0].length;
    let dp = grid[0].slice();
    for (let r = 1; r < m; r++) {
        const ndp = new Array(n).fill(Infinity);
        for (let j = 0; j < n; j++) {
            let best = Infinity;
            for (let p = 0; p < n; p++) {
                const cand = dp[p] + moveCost[grid[r - 1][p]][j];
                if (cand < best) best = cand;
            }
            ndp[j] = grid[r][j] + best;
        }
        dp = ndp;
    }
    return Math.min(...dp);
};
